static string FormatXml(XmlDocument doc)
{
    using var sw = new StringWriter();
    using var writer = new XmlTextWriter(sw);
    writer.Formatting = Formatting.Indented;
    writer.Indentation = 2;
    doc.WriteTo(writer);
    writer.Flush();
    return sw.ToString();
}

