            "CN=Enterprise SSO SAML Signing, O=Enterprise Corp, C=US",
            rsa,
            HashAlgorithmName.SHA256,
            RSASignaturePadding.Pkcs1);

        request.CertificateExtensions.Add(
            new X509KeyUsageExtension(
                X509KeyUsageFlags.DigitalSignature | X509KeyUsageFlags.KeyEncipherment,
                critical: true));

        request.CertificateExtensions.Add(
            new X509EnhancedKeyUsageExtension(
                new OidCollection
                {
                    new Oid("1.3.6.1.5.5.7.3.1"), // Server Authentication
                    new Oid("1.3.6.1.5.5.7.3.2")  // Client Authentication
                },
                critical: false));

        var certificate = request.CreateSelfSigned(
            DateTimeOffset.UtcNow.AddDays(-1),
            DateTimeOffset.UtcNow.AddYears(2));

        // Export and reimport to ensure private key is available on all platforms
        var pfxBytes = certificate.Export(X509ContentType.Pfx, "saml-temp-password");
        return new X509Certificate2(pfxBytes, "saml-temp-password",
            X509KeyStorageFlags.MachineKeySet | X509KeyStorageFlags.Exportable);
    }
